+fn make_span(start: u64, end: u64) -> SourceSpan {
+    SourceSpan {
+        start_offset: start,
+        end_offset: end,
+        start_line: 1,
+        start_column: start + 1,
+        end_line: 1,
+        end_column: end + 1,
+    }
